import{_ as i,C as A,c as l,o as t,a2 as a,b as n,w as r,a as s,G as c,a3 as u}from"./chunks/framework.lHtoIQ2D.js";const m=JSON.parse('{"title":"OAuth","description":"","frontmatter":{},"headers":[],"relativePath":"Tech/~/security/oauth.md","filePath":"Tech/~/security/oauth.md","lastUpdated":1778988489000}'),p={name:"Tech/~/security/oauth.md"};function h(E,e,C,d,B,_){const o=A("Mermaid");return t(),l("div",null,[e[1]||(e[1]=a('<h1 id="oauth" tabindex="-1">OAuth <a class="header-anchor" href="#oauth" aria-label="Permalink to &quot;OAuth&quot;">​</a></h1><blockquote><p>OAuth는 권한 위임(Authorization)를 위한 개방형 표준 프로토콜이다.</p></blockquote><p><strong>[관련 spec]</strong></p><ul><li><a href="https://datatracker.ietf.org/doc/html/rfc5849" target="_blank" rel="noreferrer">RFC 5849</a> - The OAuth 1.0 Protocol</li><li><a href="https://datatracker.ietf.org/doc/html/rfc6749" target="_blank" rel="noreferrer">RFC 6749</a> - The OAuth 2.0 Authorization Framework</li></ul><h2 id="왜-필요한가" tabindex="-1">왜 필요한가? <a class="header-anchor" href="#왜-필요한가" aria-label="Permalink to &quot;왜 필요한가?&quot;">​</a></h2><p>OAuth가 없던 시절에는 어떻게 하였나</p><p>먼저 이해하기 쉽게,</p><p>A 서비스에서 사용자의 구글 드라이브 접근권한이 필요하다고 가정해보자</p><ul><li>사용자가 A서비스에 구글 패스워드를 직접 입력함</li><li>이후 A서비스가 -&gt; 구글 API를 호출</li></ul><p>A서비스가 사용자의 패스워드를 알게 됨, A서비스를 신뢰해야하고 A가 털리면 내 정보도 털리게 됨</p><p>OAuth가 해주는 것.</p><ul><li>사용자 -&gt; 구글한테만 비밀번호 입력 (A서비스는 개입 못 함)</li><li>A서비스는 구글 드라이브 API만 호출 가능한 토큰을 받음 (패스워드는 모름)</li></ul><p>A서비스가 털려도 token만 털림, token은 패스워드와 다르게 권한의 scope가 있고 + 만료 기간이 존재</p><p>이거에 대한 표준이 OAuth인 것이다</p><h2 id="oauth-2-0" tabindex="-1">Oauth 2.0 <a class="header-anchor" href="#oauth-2-0" aria-label="Permalink to &quot;Oauth 2.0&quot;">​</a></h2><p>OAuth 1.0의 문제점을 보완하기 위해 나온 것이 OAuth 2.0 이다</p><p>OAuth 프레임웤을 이해하기 위해선 아래 개념에 대해 살펴본다</p><ul><li><p>Resource Owner: 사용자</p></li><li><p>Client: 사용자의 정보에 접근하는 제3자 서비스(A서비스)</p></li><li><p>Authorization Server: 토큰 발급 서버 (Client의 접근을 관리하는 서버)</p></li><li><p>Resource Server: 보호된 API 서버 (Resource Owner의 데이터를 관리하는 서버)</p><p>2.0버전은 1.0버전과 다르게 Grant 방식이 여러개가 있음.</p></li></ul><h3 id="authorization-code-flow" tabindex="-1">Authorization Code Flow <a class="header-anchor" href="#authorization-code-flow" aria-label="Permalink to &quot;Authorization Code Flow&quot;">​</a></h3>',19)),(t(),n(u,null,{default:r(()=>[c(o,{id:"mermaid-108",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20participant%20RO%20as%20Resource%20Owner%20(%EC%82%AC%EC%9A%A9%EC%9E%90)%0A%20%20%20%20participant%20Client%20as%20Client%20(A%EC%84%9C%EB%B9%84%EC%8A%A4)%0A%20%20%20%20participant%20AS%20as%20Authorization%20Server%0A%20%20%20%20participant%20RS%20as%20Resource%20Server%0A%0A%20%20%20%20RO-%3E%3EClient%3A%20%EB%A1%9C%EA%B7%B8%EC%9D%B8%20%ED%81%B4%EB%A6%AD%0A%20%20%20%20Client-%3E%3EAS%3A%20Authorization%20Request%0A%20%20%20%20Note%20right%20of%20Client%3A%20response_type%3Dcode%3Cbr%2F%3Eclient_id%2C%20redirect_uri%3Cbr%2F%3Escope%2C%20state%0A%20%20%20%20AS-%3E%3ERO%3A%20%EB%A1%9C%EA%B7%B8%EC%9D%B8%20%2B%20%EB%8F%99%EC%9D%98%20%ED%99%94%EB%A9%B4%0A%20%20%20%20RO-%3E%3EAS%3A%20%EC%9D%B8%EC%A6%9D%20%2B%20%EA%B6%8C%ED%95%9C%20%EB%8F%99%EC%9D%98%0A%20%20%20%20AS-%3E%3EClient%3A%20Authorization%20Code%20%EB%B0%9C%EA%B8%89%0A%20%20%20%20Note%20right%20of%20AS%3A%20redirect_uri%3Fcode%3DAUTH_CODE%26state%3D...%0A%20%20%20%20Client-%3E%3EAS%3A%20Token%20Request%0A%20%20%20%20Note%20right%20of%20Client%3A%20code%20%2B%20client_secret%0A%20%20%20%20AS-%3E%3EClient%3A%20Access%20Token%20%2B%20Refresh%20Token%20%EB%B0%9C%EA%B8%89%0A%20%20%20%20Client-%3E%3ERS%3A%20API%20%ED%98%B8%EC%B6%9C%0A%20%20%20%20Note%20right%20of%20Client%3A%20Authorization%3A%20Bearer%20access_token%0A%20%20%20%20RS-%3E%3EClient%3A%20%EB%B3%B4%ED%98%B8%EB%90%9C%20%EB%A6%AC%EC%86%8C%EC%8A%A4%20%EC%9D%91%EB%8B%B5%0A"})]),fallback:r(()=>e[0]||(e[0]=[s(" Loading... ")])),_:1})),e[2]||(e[2]=a("<p>RFC 스펙을 살펴보면 Client는 두종류로 나뉨</p><p><strong>confidential</strong>: credential을 안전하게 보관할 수 있는 Client (백엔드 서버가 있는 환경)<br><strong>public</strong>: 보관 못 하는 Client (설치형 앱, 브라우저 앱)</p><p>위의 flow는 <strong>confidentail</strong>의 경우이고, <strong>public</strong>의 경우 <code>client_secret</code>이 노출되기 때문에 인증이 되지 못함<br> 그래서 스펙에서 public client에게 secret 기반 인증을 요구하지 않음</p>",3))])}const g=i(p,[["render",h]]);export{m as __pageData,g as default};
